        if (nums[i] === 1) {
            onesIndices.push(i);
        } else if (nums[i] === 2) {
            twosIndices.push(i);
        }
    }

    // 2. Check if any valid pair exists
    if (onesIndices.length === 0 || twosIndices.length === 0) {
        return -1;
    }

    // 3. Sort indices (though they are collected in increasing order, explicit sort ensures robustness if logic were changed)
    // Since we iterate linearly, they are already sorted by index.

    let minDiff = Infinity;

    // 4. Find the minimum absolute difference
    // We need to check every pair (i_one, i_two) where i_one is from onesIndices and i_two is from twosIndices.

    // Optimization: Since we are looking for the minimum difference between two sorted lists,
    // we can use a two-pointer approach instead of O(N1 * N2).

    let p1 = 0; // Pointer for onesIndices
    let p2 = 0; // Pointer for twosIndices

    while (p1 < onesIndices.length && p2 < twosIndices.length) {
        const i = onesIndices[p1];
        const j = twosIndices[p2];

        // Calculate current absolute difference
        const currentDiff = Math.abs(i - j);
        minDiff = Math.min(minDiff, currentDiff);

        // Move the pointer associated with the smaller index, 
        // as moving the pointer associated with the larger index will only increase the distance 
        // (or keep it the same if the difference was 0, but we still need to check neighbors).
        if (i < j) {
            p1++; // Try to increase i to get closer to j
        } else {
            p2++; // Try to increase j to get closer to i
        }
    }

    // Since we already checked that both lists are non-empty, minDiff must be updated.
    return minDiff;
